//leer cookies
function getCookieGA(cname) {
    var name = cname + "=";
    var decodedCookie = decodeURIComponent(document.cookie);
    var ca = decodedCookie.split(';');
    for (var i = 0; i < ca.length; i++) {
        var c = ca[i];
        while (c.charAt(0) === ' ') {
            c = c.substring(1);
        }
        if (c.indexOf(name) === 0) {
            var arrayCookie = c.substring(name.length, c.length);
            return arrayCookie.includes('_ga');
            //return c.substring(name.length, c.length);
        }
    }
    return "";
}
