// Función para actualizar las clases "hidden" y "hidden-desktop" según resolución y así no perder el foco
let resizeTimer;
function actualizarClasesHidden() {
  const navigation = document.getElementById('navigation');
  if (!navigation) return;

  const isDesktop = window.matchMedia('(min-width: 768px)').matches;

  navigation.querySelectorAll('div.gpa-nav-list-parent').forEach(div => {
    if (isDesktop) {
        if (div.classList.contains('hidden')) {
            div.classList.remove('hidden');
            div.classList.add('hidden-desktop');
        }
    } else {
        if (div.contains('hidden-desktop')) {
            div.classList.remove('hidden-desktop');
            div.classList.add('hidden');
        }
    }
  });
}

document.addEventListener('DOMContentLoaded', actualizarClasesHidden);


window.addEventListener('resize', function() {
  clearTimeout(resizeTimer);
  resizeTimer = setTimeout(actualizarClasesHidden, 250);
});

window.addEventListener('orientationchange', actualizarClasesHidden);

