(function() {
    const h1Actual = document.querySelector('h1.h1-driu_');
    if (h1Actual) {
        const h1Anteriores = document.querySelectorAll('h1:not(.h1-driu_)').length;
        if (h1Anteriores > 0) {
            const h2Nuevo = document.createElement('h2');
            h2Nuevo.className = h1Actual.className;
            h2Nuevo.innerHTML = h1Actual.innerHTML;
            Object.assign(h2Nuevo.dataset, h1Actual.dataset);
            h1Actual.replaceWith(h2Nuevo);
        }
    }
})();

